<template><el-card><template #header><b>{{processed?'已办审批':'待办审批'}}</b></template><el-table :data="rows" v-loading="loading"><el-table-column prop="approvalNo" label="审批编号" width="230"/><el-table-column prop="applicationNo" label="申请编号" width="230"/><el-table-column prop="title" label="标题"/><el-table-column prop="applicantName" label="申请人"/><el-table-column prop="status" label="状态"/><el-table-column label="操作"><template #default="{row}"><el-button link type="primary" @click="$router.push(`/approvals/${row.approvalId}`)">详情</el-button></template></el-table-column></el-table></el-card></template>
<script setup>import{computed,ref,watch}from'vue';import{useRoute}from'vue-router';import{listPending,listProcessed}from'../../api/approvals';const route=useRoute(),processed=computed(()=>Boolean(route.meta.processed)),rows=ref([]),loading=ref(false);async function load(){loading.value=true;try{rows.value=processed.value?await listProcessed():await listPending()}finally{loading.value=false}}watch(()=>route.fullPath,load,{immediate:true})</script>
